fields.BacktestEngineNode.items.help_tex:
Specify source array in 'from', then map fields in 'extract'.

Example:
from: {{ nodes.historical.values }}
extract:
  close: {{ row.close }}
  signal: {{ row.signal }}

fields.ConditionNode.items.help_text:
Specify source array in 'from', then map fields in 'extract'.

Example:
from: {{ nodes.historical.values }}
extract:
  symbol: {{ row.symbol }}
  close: {{ row.close }}

